     2→
     3→namespace App\Http\Controllers;
     4→
     5→use App\Models\Project;
     6→use App\Models\Task;
     7→use Illuminate\Http\Request;
     8→
     9→class TaskController extends Controller
    10→{
    11→    public function show(Task $task)
    12→    {
    13→        $this->authorize('update', $task);
    14→        $task->load([
    15→            'subtasks' => fn ($q) => $q->whereNull('parent_id')->with('children'),
    16→            'tags',
    17→        ]);
    18→        return response()->json($task);
    19→    }
    20→
    21→    public function store(Request $request, Project $project)
    22→    {
    23→        $this->authorize('update', $project);
    24→
    25→        $validated = $request->validate([
    26→            'title'                      => 'required|string|max:255',
    27→            'description'                => 'nullable|string',
    28→            'priority'                   => 'required|in:high,medium,low',
    29→            'estimated_hours'            => 'nullable|numeric|min:0',
    30→            'status'                     => 'required|in:backlog,in_progress,testing,done',
    31→            'subtasks'                   => 'nullable|array',
    32→            'subtasks.*.title'           => 'required|string|max:255',
    33→            'subtasks.*.estimated_hours' => 'nullable|numeric|min:0',
    34→        ]);
    35→
    36→        $maxPosition = $project->tasks()->where('status', $validated['status'])->max('position') ?? -1;
    37→        $validated['position'] = $maxPosition + 1;
    38→
    39→        $task = $project->tasks()->create(
    40→            collect($validated)->except('subtasks')->toArray()
    41→        );
    42→
    43→        foreach ($validated['subtasks'] ?? [] as $subtaskData) {
    44→            $task->subtasks()->create($subtaskData);
    45→        }
    46→
    47→        return redirect()->route('projects.show', $project)->with('success', 'Tarea creada.');
    48→    }
    49→
    50→    public function update(Request $request, Task $task)
    51→    {
    52→        $this->authorize('update', $task);
    53→
    54→        $validated = $request->validate([
    55→            'title' => 'required|string|max:255',
    56→            'description' => 'nullable|string',
    57→            'priority' => 'required|in:high,medium,low',
    58→            'estimated_hours' => 'nullable|numeric|min:0',
    59→            'status' => 'required|in:backlog,in_progress,testing,done',
    60→        ]);
    61→
    62→        $task->update($validated);
    63→
    64→        if ($request->wantsJson()) {
    65→            return response()->json(['success' => true, 'task' => $task]);
    66→        }
    67→
    68→        return redirect()->route('projects.show', $task->project_id)->with('success', 'Tarea actualizada.');
    69→    }
    70→
    71→    public function updateStatus(Request $request, Task $task)
    72→    {
    73→        $this->authorize('update', $task);
    74→
    75→        $validated = $request->validate([
    76→            'status' => 'required|in:backlog,in_progress,testing,done',
    77→            'position' => 'nullable|integer|min:0',
    78→        ]);
    79→
    80→        $task->update($validated);
    81→
    82→        return response()->json(['success' => true]);
    83→    }
    84→
    85→    public function reorder(Request $request)
    86→    {
    87→        $validated = $request->validate([
    88→            'tasks' => 'required|array',
    89→            'tasks.*.id' => 'required|integer|exists:tasks,id',
    90→            'tasks.*.position' => 'required|integer|min:0',
    91→            'tasks.*.status' => 'required|in:backlog,in_progress,testing,done',
    92→        ]);
    93→
    94→        foreach ($validated['tasks'] as $item) {
    95→            $task = Task::find($item['id']);
    96→            if ($task) {
    97→                $this->authorize('update', $task);
    98→                $task->update(['position' => $item['position'], 'status' => $item['status']]);
    99→            }
   100→        }
   101→
   102→        return response()->json(['success' => true]);
   103→    }
   104→
   105→    public function destroy(Task $task)
   106→    {
   107→        $this->authorize('delete', $task);
   108→        $projectId = $task->project_id;
   109→        $task->delete();
   110→
   111→        if (request()->wantsJson()) {
   112→            return response()->json(['success' => true]);
   113→        }
   114→
   115→        return redirect()->route('projects.show', $projectId)->with('success', 'Tarea eliminada.');
   116→    }
   117→}
   118→

